import{_ as e,f as t}from"./app.96040f5d.js";var s="/images/github-pages-settings.png",i="/images/github-pages-option.png",a="/images/github-pages-dropdown.png",o="/images/github-pages-url.png",r="/images/github-pages-test.png";const n={},g=t('<h1 id="github-pages" tabindex="-1"><a class="header-anchor" href="#github-pages" aria-hidden="true">#</a> GitHub Pages</h1><p>GitHub Pages is a static site hosting service designed to host your personal, organization, or project pages directly from a GitHub repository.</p><p>In the previous course you used the GitHub Pages by creating a repository with username.github.io where <em>username</em> is your GitHub.com username. This is one way of automatically setting up GitHub Pages site, although this is limited to only one repository as you can only create a single repository with that name.</p><p>We will look into how we can setup any repository to be hosted on GitHub pages as a static site.</p><p>Once we have created our <strong>public</strong> repository, we can go into the settings of the repository. <img src="'+s+'" alt="GitHub Pages Settings"></p><p>Select <strong>Pages</strong> from the left side menu. <img src="'+i+'" alt="GitHub Pages page options tab"></p><p>Select <strong>main</strong> from the dropdown menu and save. <img src="'+a+'" alt="GitHub Pages selecting main branch"></p><p>You will see a URL for your GitHub Pages site for this repository. <img src="'+o+'" alt="GitHub Pages url option"></p><p>Try accessing the URL in a few minutes to see the <code>index.html</code> page being displayed in the browser. This may take a few minutes to make your site available live, <img src="'+r+'" alt="GitHub Pages test the url"></p><p>You have successfully hosted your repository in GitHub Pages. If this is not working please note the following troubleshooting steps:</p><ul><li>Check that the file name is index.html all lowercase</li><li>Check that your index.html file has some content</li></ul>',11);function p(u,h){return g}var c=e(n,[["render",p]]);export{c as default};
